// ==========================================================================
// State
// ==========================================================================
const STORAGE_KEY = "loj_lang";

function detectLang(){
  try {
    const saved = localStorage.getItem(STORAGE_KEY);
    if(saved && SUPPORTED_LANGS.includes(saved)) return saved;
  } catch(e){}
  const nav = (navigator.language || "en").toLowerCase();
  if(nav.startsWith("tr")) return "tr";
  if(nav.startsWith("fr")) return "fr";
  if(nav.startsWith("ja")) return "ja";
  return "en";
}

let currentLang = detectLang();
let currentFilter = "all";

// ==========================================================================
// Render logic
// ==========================================================================
const $ = (sel, root=document) => root.querySelector(sel);
const $$ = (sel, root=document) => Array.from(root.querySelectorAll(sel));

function data(){ return LANG_DATA[currentLang]; }
function strings(){ return UI_STRINGS[currentLang]; }

function guideById(id){ return data().GUIDES.find(g => g.id === id); }

function renderNav(){
  const nav = $("#nav");
  const CATS = data().CATS;
  const GUIDES = data().GUIDES;
  let html = "";
  Object.keys(CATS).forEach(catKey => {
    const cat = CATS[catKey];
    const items = GUIDES.filter(g => g.cat === catKey);
    html += `<div class="nav-group">
      <div class="nav-group-label">${cat.icon} ${cat.label}</div>
      ${items.map(g => `
        <div class="nav-item" data-id="${g.id}" role="link" tabindex="0">
          <span class="ic">${g.icon}</span><span class="lbl">${g.title}</span>
        </div>`).join("")}
    </div>`;
  });
  nav.innerHTML = html;
  $$(".nav-item", nav).forEach(el => {
    el.addEventListener("click", () => goTo(el.dataset.id));
    el.addEventListener("keypress", e => { if(e.key === "Enter") goTo(el.dataset.id); });
  });
}

function cardTemplate(g){
  const cat = data().CATS[g.cat];
  const s = strings();
  return `<div class="card" data-id="${g.id}" tabindex="0" role="link">
    <div class="card-top">
      <div class="card-icon">${g.icon}</div>
      <div class="card-badge ${cat.badge}">${cat.label}</div>
    </div>
    <h3>${g.title}</h3>
    <p>${g.tagline}</p>
    <div class="card-foot"><span>${g.tags.slice(0,2).join(" · ")}</span><span class="go">${s.cardGo}</span></div>
  </div>`;
}

function renderOverview(){
  const grid = $("#overview-grid");
  grid.innerHTML = data().GUIDES.map(cardTemplate).join("");
  bindCards(grid);
}

function bindCards(root){
  $$(".card", root).forEach(el => {
    el.addEventListener("click", () => goTo(el.dataset.id));
    el.addEventListener("keypress", e => { if(e.key === "Enter") goTo(el.dataset.id); });
  });
}

function applyFilter(catKey){
  currentFilter = catKey;
  $$(".chip").forEach(c => c.classList.toggle("active", c.dataset.filter === catKey));
  const grid = $("#overview-grid");
  const GUIDES = data().GUIDES;
  const list = catKey === "all" ? GUIDES : GUIDES.filter(g => g.cat === catKey);
  grid.innerHTML = list.length ? list.map(cardTemplate).join("") : `<div class="empty-state">${strings().noRecords}</div>`;
  bindCards(grid);
}

function renderDetail(id){
  const g = guideById(id);
  if(!g){ goTo(null); return; }
  const CATS = data().CATS;
  const GUIDES = data().GUIDES;
  const s = strings();
  const cat = CATS[g.cat];
  const idx = GUIDES.indexOf(g);
  const prev = GUIDES[(idx - 1 + GUIDES.length) % GUIDES.length];
  const next = GUIDES[(idx + 1) % GUIDES.length];

  $("#detail-view").innerHTML = `
    <div class="detail">
      <div class="detail-head">
        <div class="hazard-line"></div>
        <button class="back-btn" id="back-btn">${s.backBtn}</button>
        <div class="dh-top">
          <div class="dh-icon">${g.icon}</div>
          <div class="dh-titles">
            <span class="dh-cat ${cat.badge}">${cat.icon} ${cat.label}</span>
            <h1>${g.title}</h1>
          </div>
        </div>
        <p class="dh-lead">${g.tagline}</p>
        <div class="dh-tags">${g.tags.map(t => `<span class="dtag">${t}</span>`).join("")}</div>
      </div>
      <div class="detail-body">
        ${g.body}
      </div>
      <div class="detail-nav-end">
        <div class="nav-end-btn" id="prev-btn"><div class="lbl">${s.prevLabel}</div><div class="ttl">${prev.icon} ${prev.title}</div></div>
        <div class="nav-end-btn right" id="next-btn"><div class="lbl">${s.nextLabel}</div><div class="ttl">${next.icon} ${next.title}</div></div>
      </div>
    </div>
  `;

  $("#back-btn").addEventListener("click", () => goTo(null));
  $("#prev-btn").addEventListener("click", () => goTo(prev.id));
  $("#next-btn").addEventListener("click", () => goTo(next.id));

  $$(".code-chip", $("#detail-view")).forEach(chip => {
    chip.addEventListener("click", () => {
      const code = chip.dataset.code;
      navigator.clipboard?.writeText(code).catch(()=>{});
      chip.classList.add("copied");
      const cp = $(".cp", chip);
      const original = cp.textContent;
      cp.textContent = strings().copied;
      setTimeout(() => { chip.classList.remove("copied"); cp.textContent = original; }, 1400);
    });
  });

  window.scrollTo({ top: 0, behavior: "instant" in window ? "instant" : "auto" });
}

function setActiveNav(id){
  $$(".nav-item").forEach(el => el.classList.toggle("active", el.dataset.id === id));
}

function goTo(id){
  if(id){
    location.hash = id;
  } else {
    location.hash = "";
  }
}

function route(){
  const id = location.hash.replace("#","");
  const overview = $("#overview-view");
  const detail = $("#detail-view");
  if(id && guideById(id)){
    overview.classList.remove("active");
    detail.classList.add("active");
    renderDetail(id);
    setActiveNav(id);
  } else {
    detail.classList.remove("active");
    overview.classList.add("active");
    setActiveNav(null);
  }
  closeMobileNav();
}

function initFilters(){
  $$(".chip").forEach(chip => {
    chip.addEventListener("click", () => applyFilter(chip.dataset.filter));
  });
}

function initSearch(){
  const input = $("#search-input");
  input.addEventListener("input", () => {
    const q = input.value.trim().toLowerCase();
    $$(".nav-item").forEach(el => {
      const g = guideById(el.dataset.id);
      const hit = !q || g.title.toLowerCase().includes(q) || g.tagline.toLowerCase().includes(q) || g.tags.join(" ").toLowerCase().includes(q);
      el.style.display = hit ? "flex" : "none";
    });
  });
}

function openMobileNav(){ $(".sidebar").classList.add("open"); $(".scrim").classList.add("show"); }
function closeMobileNav(){ $(".sidebar").classList.remove("open"); $(".scrim")?.classList.remove("show"); }

function initMobile(){
  $("#nav-toggle")?.addEventListener("click", openMobileNav);
  $(".scrim")?.addEventListener("click", closeMobileNav);
}

// ==========================================================================
// i18n — static text + language switcher
// ==========================================================================
function applyStaticI18n(){
  const s = strings();

  document.documentElement.lang = s.htmlLang;
  document.title = s.pageTitle;
  $('meta[name="description"]')?.setAttribute("content", s.metaDesc);

  const set = (sel, val, isHTML=false) => {
    const el = $(sel);
    if(!el) return;
    if(isHTML) el.innerHTML = val; else el.textContent = val;
  };

  set("#mobile-brand-tag", s.mobileBrandTag);
  set("#nav-toggle", s.navToggle);
  set("#brand-desc", s.brandDesc);
  set("#sidebar-foot", s.sidebarFoot, true);
  set("#hero-eyebrow", s.heroEyebrow);
  set("#hero-title", s.heroTitle, true);
  set("#hero-lead", s.heroLead);
  set("#section-title", s.sectionTitle);
  set("#section-note", s.sectionNote);
  set("#footer-source", s.footerSource, true);

  const input = $("#search-input");
  if(input){ input.placeholder = s.searchPlaceholder; input.setAttribute("aria-label", s.searchAria); }
  $("#nav")?.setAttribute("aria-label", s.navAria);

  const statEls = $$(".hstat span");
  s.statLabels.forEach((label, i) => { if(statEls[i]) statEls[i].textContent = label; });

  $$(".chip").forEach(chip => {
    const key = chip.dataset.filter;
    if(s.filters[key]) chip.textContent = s.filters[key];
  });
}

function renderLangSwitcher(){
  const html = SUPPORTED_LANGS.map(l => {
    const meta = LANG_META[l];
    const active = l === currentLang ? " active" : "";
    return `<button class="lang-btn${active}" data-lang="${l}" title="${meta.name}">${meta.flag} ${meta.code}</button>`;
  }).join("");
  $$(".lang-switch").forEach(el => { el.innerHTML = html; });
  $$(".lang-btn").forEach(btn => {
    btn.addEventListener("click", () => setLang(btn.dataset.lang));
  });
}

function setLang(lang){
  if(!SUPPORTED_LANGS.includes(lang) || lang === currentLang) return;
  currentLang = lang;
  try { localStorage.setItem(STORAGE_KEY, lang); } catch(e){}

  applyStaticI18n();
  renderLangSwitcher();
  renderNav();

  const input = $("#search-input");
  if(input) input.value = "";

  const id = location.hash.replace("#","");
  if(id && guideById(id)){
    renderDetail(id);
    setActiveNav(id);
  } else {
    applyFilter(currentFilter);
  }
}

// ==========================================================================
// Init
// ==========================================================================
document.addEventListener("DOMContentLoaded", () => {
  applyStaticI18n();
  renderLangSwitcher();
  renderNav();
  renderOverview();
  initFilters();
  initSearch();
  initMobile();
  window.addEventListener("hashchange", route);
  route();
});
